const wait = (ms, tag) =>
  new Promise((r) => setTimeout(() => { console.log(tag); r(); }, ms));

// 版本一：逐一等
async function seq() {
  await wait(50, "A");
  await wait(10, "B");
}

// 版本二：先全部啟動再等
async function par() {
  const a = wait(50, "A");
  const b = wait(10, "B");
  await a;
  await b;
}

